INSERT INTO `integral_goods` VALUES (5,4,'https://api.lumoguide.com/storage/images/20251110/5dd659d3a96b7c929862f06528aca3ad.jpeg','[\"https:\\/\\/api.lumoguide.com\\/storage\\/images\\/20251110\\/5dd659d3a96b7c929862f06528aca3ad.jpeg\"]','酒店房券',2,10000,1,1,NULL,0,0,100,0,'2025-11-09 11:35:34','2026-02-27 01:17:29'),(6,4,'https://api.lumoguide.com/storage/images/20251110/5e5fe15a7b03f8ff461505cf8ca4f72a.jpeg','[\"https:\\/\\/api.lumoguide.com\\/storage\\/images\\/20251110\\/5e5fe15a7b03f8ff461505cf8ca4f72a.jpeg\"]','南藥湯泉票',2,10000,0,1,NULL,0,0,100,0,'2025-11-09 11:36:07','2026-02-27 01:17:16'),(7,4,'https://api.lumoguide.com/storage/images/20260222/3476a5c55efe48803180aaf6859e2094.webp','[\"https:\\/\\/api.lumoguide.com\\/storage\\/images\\/20260222\\/3476a5c55efe48803180aaf6859e2094.webp\",\"https:\\/\\/api.lumoguide.com\\/storage\\/images\\/20260222\\/adeb913241393185065cf9943fb4b536.jpg\",\"https:\\/\\/api.lumoguide.com\\/storage\\/images\\/20260222\\/3e92da968dd8636eedb8c16380efe06c.jpg\",\"https:\\/\\/api.lumoguide.com\\/storage\\/images\\/20260222\\/9252fb628880e4a25bef61227fe6e99a.webp\",\"https:\\/\\/api.lumoguide.com\\/storage\\/images\\/20260222\\/37e950d9cfe2a0f7f3d1826532caaf30.webp\",\"https:\\/\\/api.lumoguide.com\\/storage\\/images\\/20260222\\/c9a03442acf6d495e76dc612976769ae.jpg\",\"https:\\/\\/api.lumoguide.com\\/storage\\/images\\/20260222\\/80522eff737f10c20817c932efb1afa4.webp\"]','TUI ALPHA BRAVO Surveillance Rolltop Rucksack',1,59500,1,0,'<h3 data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">產品描述</strong></h3>\r\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">為卓越性能而生</strong>：這款掀蓋式後背包經過全新升級改良。寬敞的收納空間讓您無論是日常通勤、單日郊遊還是長週末旅行，都能輕鬆裝箱、自在出行。</p>\r\n<ul data-path-to-node=\"4\">\r\n<li>\r\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">材質</strong>：彈道尼龍 (Ballistic Nylon)</p>\r\n</li>\r\n<li>\r\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">款式編號</strong>：156488-1041</p>\r\n</li>\r\n</ul>\r\n<hr data-path-to-node=\"5\" />\r\n<h3 data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">外部配置</strong></h3>\r\n<ul data-path-to-node=\"7\">\r\n<li>\r\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">主隔層</strong>：拉鍊開口設計</p>\r\n</li>\r\n<li>\r\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">頂部設計</strong>：捲頂式掀蓋，配備 <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"14\">Fidlock® 磁扣</strong></p>\r\n</li>\r\n<li>\r\n<p data-path-to-node=\"7,2,0\"><strong data-path-to-node=\"7,2,0\" data-index-in-node=\"0\">提把</strong>：皮革包覆頂部提把</p>\r\n</li>\r\n<li>\r\n<p data-path-to-node=\"7,3,0\"><strong data-path-to-node=\"7,3,0\" data-index-in-node=\"0\">背部</strong>：3D 網面背板，提升佩戴舒適度</p>\r\n</li>\r\n<li>\r\n<p data-path-to-node=\"7,4,0\"><strong data-path-to-node=\"7,4,0\" data-index-in-node=\"0\">擴充系統</strong>：左右前側口袋與上方肩帶設有 <strong data-path-to-node=\"7,4,0\" data-index-in-node=\"19\">Daisy Chain 織帶環</strong>，兼容 TUMI+ 外掛配件（需另購）</p>\r\n</li>\r\n<li>\r\n<p data-path-to-node=\"7,5,0\"><strong data-path-to-node=\"7,5,0\" data-index-in-node=\"0\">收納口袋</strong>：</p>\r\n<ul data-path-to-node=\"7,5,1\">\r\n<li>\r\n<p data-path-to-node=\"7,5,1,0,0\">前方水平拉鍊口袋</p>\r\n</li>\r\n<li>\r\n<p data-path-to-node=\"7,5,1,1,0\">右側開放式口袋</p>\r\n</li>\r\n<li>\r\n<p data-path-to-node=\"7,5,1,2,0\">背部隱藏式磁吸快取口袋</p>\r\n</li>\r\n</ul>\r\n</li>\r\n<li>\r\n<p data-path-to-node=\"7,6,0\"><strong data-path-to-node=\"7,6,0\" data-index-in-node=\"0\">細節設計</strong>：</p>\r\n<ul data-path-to-node=\"7,6,1\">\r\n<li>\r\n<p data-path-to-node=\"7,6,1,0,0\">可刻字銘牌 (Monogram Patch)</p>\r\n</li>\r\n<li>\r\n<p data-path-to-node=\"7,6,1,1,0\">行李吊牌</p>\r\n</li>\r\n<li>\r\n<p data-path-to-node=\"7,6,1,2,0\"><strong data-path-to-node=\"7,6,1,2,0\" data-index-in-node=\"0\">Add-a-Bag 系統</strong>（可將背包固定於行李箱拉桿）</p>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<hr data-path-to-node=\"8\" />\r\n<h3 data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">內部配置</strong></h3>\r\n<ul data-path-to-node=\"10\">\r\n<li>\r\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">收納細節</strong>：</p>\r\n<ul data-path-to-node=\"10,0,1\">\r\n<li>\r\n<p data-path-to-node=\"10,0,1,0,0\">內置鑰匙扣繩</p>\r\n</li>\r\n<li>\r\n<p data-path-to-node=\"10,0,1,1,0\">筆槽</p>\r\n</li>\r\n<li>\r\n<p data-path-to-node=\"10,0,1,2,0\">分隔前後隔層的中央拉鍊袋</p>\r\n</li>\r\n<li>\r\n<p data-path-to-node=\"10,0,1,3,0\">2 個卡片槽</p>\r\n</li>\r\n<li>\r\n<p data-path-to-node=\"10,0,1,4,0\">3 個開放式多媒體收納袋</p>\r\n</li>\r\n</ul>\r\n</li>\r\n<li>\r\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">科技設備保護</strong>：</p>\r\n<ul data-path-to-node=\"10,1,1\">\r\n<li>\r\n<p data-path-to-node=\"10,1,1,0,0\">加墊平板電腦專用隔層</p>\r\n</li>\r\n<li>\r\n<p data-path-to-node=\"10,1,1,1,0\">加墊筆電專用隔層（最高可容納 <strong data-path-to-node=\"10,1,1,1,0\" data-index-in-node=\"15\">15 吋 PC</strong> 或 <strong data-path-to-node=\"10,1,1,1,0\" data-index-in-node=\"25\">16 吋 MacBook</strong>）</p>\r\n</li>\r\n</ul>\r\n</li>\r\n<li>\r\n<p data-path-to-node=\"10,2,0\"><strong data-path-to-node=\"10,2,0\" data-index-in-node=\"0\">擴充設計</strong>：內部設有兼容 TUMI+ 的織帶環（需另購）</p>\r\n</li>\r\n<li>\r\n<p data-path-to-node=\"10,3,0\"><strong data-path-to-node=\"10,3,0\" data-index-in-node=\"0\">專屬追蹤</strong>：<strong data-path-to-node=\"10,3,0\" data-index-in-node=\"5\">TUMI Tracer® 全球註冊追蹤系統</strong></p>\r\n</li>\r\n</ul>',0,0,10,1,'2025-11-09 11:36:32','2026-02-22 10:42:46');


