INSERT INTO `system_config` VALUES (1,'用戶協議',2,'user_protocol','<p class=\"a\" style=\"text-align: center; line-height: 240%; margin: 0cm 0cm 16.5pt 0cm;\" align=\"center\"><strong><span lang=\"ZH-TW\" style=\"font-size: 22.0pt; line-height: 240%; font-family: 宋体; mso-bidi-font-family: 宋体;\">《用戶協議》</span></strong></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; line-height: normal;\"><strong><span lang=\"JA\" style=\"font-size: 14.0pt; font-family: 宋体; mso-bidi-font-family: 宋体; color: #303030; mso-ansi-language: JA; mso-fareast-language: JA;\">概述</span></strong><strong><span lang=\"JA\" style=\"font-size: 10.5pt; font-family: 宋体; mso-bidi-font-family: 宋体; color: #303030;\"> </span></strong></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: 宋体; mso-bidi-font-family: 宋体;\">路盟（Lumoguide）用戶協議（以下簡稱「本協議」）適用於 </span><span lang=\"EN-US\" style=\"font-size: 11.0pt; font-family: 宋体; mso-bidi-font-family: 宋体; mso-ansi-language: EN-US;\">GUANPEI ZHOU </span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: 宋体; mso-bidi-font-family: 宋体;\">個人公司運營和管理（以下簡稱「我們」，「本公司」）旗下的產品與服務（以下簡稱「本產品」），如果某項產品與服務有單獨的服務規則，則該產品的服務規則優先適用。本協議是您（個人或單一實體）與本公司之間就使用本產品達成的具有法律 約束力的法律協議。該法律協議包括但不限於本頁面的全部條款以及我們針對特定產品部分功能單獨發佈的政策或服務規則等（若有）。</span></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: normal; margin: 0cm 0cm 13.0pt 0cm;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: 宋体; mso-bidi-font-family: 宋体;\">請您在使用本產品之前仔細閱讀下列條款。您下載、安裝或使用產本品或者單擊「 我同意」表明您已經閱讀本協議並充分理解、遵守本協議所有條款，包括涉及免除或者限制本公司責任的免責條款、用戶權利限制條款、約定爭議解決方式等，這些條款均用粗體字標注。如果您不同意本協議的全部或部分內容，請不要下載、安裝和使用本產品。 </span></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: 172%; margin: 0cm 0cm 14.0pt 0cm;\"><strong><span lang=\"ZH-TW\" style=\"font-size: 16.0pt; line-height: 172%; font-family: 宋体; mso-bidi-font-family: 宋体;\">1. 權利聲明 </span></strong></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: 155%; margin: 0cm 0cm 14.5pt 0cm;\"><strong><span lang=\"ZH-TW\" style=\"font-size: 14.0pt; line-height: 155%; font-family: 宋体; mso-bidi-font-family: 宋体;\">1.1 知識產權 </span></strong></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: normal; margin: 0cm 0cm 14.0pt 0cm;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: 宋体; mso-bidi-font-family: 宋体;\">本公司擁有「本產品」的所有權和知識產權等全部權利。本產品受中國及其他國家的知識產權法、國際知識產權 公約（包括但不限於著作權法、商標法、專利法等）的保護。所有未授予您的權利均被本公司保留，您不可以從本產品上移除本公司的版權標記或其他權利聲明。 </span></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: 155%; margin: 0cm 0cm 14.5pt 0cm;\"><strong><span lang=\"ZH-TW\" style=\"font-size: 14.0pt; line-height: 155%; font-family: 宋体; mso-bidi-font-family: 宋体;\">1.2 軟件所有權保留 </span></strong></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: normal; margin: 0cm 0cm 13.0pt 0cm;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: 宋体; mso-bidi-font-family: 宋体;\">您確定不享有本軟件的所有權，本軟件未被出售給用戶，本公司保留本軟件的所有權。 </span></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: 172%; margin: 0cm 0cm 14.0pt 0cm;\"><strong><span lang=\"ZH-TW\" style=\"font-size: 16.0pt; line-height: 172%; font-family: 宋体; mso-bidi-font-family: 宋体;\">2. 授權許可 </span></strong></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: 155%; margin: 0cm 0cm 14.5pt 0cm;\"><strong><span lang=\"ZH-TW\" style=\"font-size: 14.0pt; line-height: 155%; font-family: 宋体; mso-bidi-font-family: 宋体;\">2.1 授權許可 </span></strong></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: normal; margin: 0cm 0cm 14.0pt 0cm;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: 宋体; mso-bidi-font-family: 宋体;\">本公司授予您一項非排他的、不可轉讓的、非商業性的、可撤銷的許可，以下載、安裝、備份和使用本產品。本公司授予您僅出於個人非商業目在移動設備上使用本產品，如果您希望將本產品用於其他非本公司授權的目的或其他商業目的，您必須另行取得本公司的單獨書面許可。 </span></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: 155%; margin: 0cm 0cm 14.5pt 0cm;\"><strong><span lang=\"ZH-TW\" style=\"font-size: 14.0pt; line-height: 155%; font-family: 宋体; mso-bidi-font-family: 宋体;\">2.2 </span></strong><strong><span style=\"font-size: 14.0pt; line-height: 155%; font-family: 宋体; mso-bidi-font-family: 宋体; mso-ansi-language: ZH-CN; mso-fareast-language: ZH-CN;\">限制</span></strong></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: normal; margin: 0cm 0cm 13.0pt 0cm;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: 宋体; mso-bidi-font-family: 宋体;\">除非就某些第三方軟件軟件有明文規定或適用法律允許，否則您不得在未取得本公司書面許可的情況下修改、翻譯、反向匯編、反向工程、反編譯本軟件的部分或全部。 </span></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: 172%; margin: 0cm 0cm 13.0pt 0cm;\"><strong><span lang=\"ZH-TW\" style=\"font-size: 16.0pt; line-height: 172%; font-family: 宋体; mso-bidi-font-family: 宋体;\">3. 用戶行為 </span></strong></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: 宋体; mso-bidi-font-family: 宋体;\">3.1 如果您在使用本公司產品或服務的過程中發佈相關用戶內容，您需要對自己發佈的所有用戶內容負責。用戶 內容是指您發佈或以其他方式使用本產品時產生的所有內容（例如：您的信息、聲音、圖片或其他內容）。您是您的用戶內容唯一的責任人，您將承擔因您的用戶內容違法法律、侵犯第三方權益的所有法律責任。</span></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: 宋体; mso-bidi-font-family: 宋体;\"><span style=\"mso-spacerun: yes;\">&nbsp;</span></span></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: 宋体; mso-bidi-font-family: 宋体;\">3.2 在使用過程中，您將承擔因下述行為而產生的全部法律責任，本公司不對您的下述行為承擔任何責任： </span></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: 宋体; mso-bidi-font-family: 宋体;\">&nbsp;</span></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: 宋体; mso-bidi-font-family: 宋体;\">破壞憲法所確定的基本原則的； </span></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: 宋体; mso-bidi-font-family: 宋体;\">危害國家安全、洩露國家秘密、顛覆國家政權、破壞國家統一的； </span></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: 宋体; mso-bidi-font-family: 宋体;\">損害國家榮譽和利益的； </span></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: 宋体; mso-bidi-font-family: 宋体;\">煽動民族仇恨、民族歧視，破壞民族團結的； </span></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: 宋体; mso-bidi-font-family: 宋体;\">破壞國家宗教政策，宣揚邪教和封建迷信的； </span></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: 宋体; mso-bidi-font-family: 宋体;\">散布謠言，擾亂社會秩序，破壞社會穩定的； </span></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: 宋体; mso-bidi-font-family: 宋体;\">散布淫穢、色情、賭博、暴力、凶殺、恐怖或者教唆犯罪的； </span></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: 宋体; mso-bidi-font-family: 宋体;\">侮辱或者誹謗他人，侵害他人合法權益的； </span></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: 宋体; mso-bidi-font-family: 宋体;\">含有法律、行政法規禁止的其他內容的。 </span></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: 宋体; mso-bidi-font-family: 宋体;\">&nbsp;</span></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: 宋体; mso-bidi-font-family: 宋体;\">3.3 您同意不通過本產品從事下列行為： </span></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: 宋体; mso-bidi-font-family: 宋体;\">&nbsp;</span></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: 宋体; mso-bidi-font-family: 宋体;\">發佈或分享電腦病毒、蠕蟲、惡意代碼、故意破壞或改變計算機系統或數據的軟件； </span></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: 宋体; mso-bidi-font-family: 宋体;\">未經授權，收集其他用戶的信息或數據，例如非法收集第三人的個人信息侵犯第三人隱私或其他合法民事權益； </span></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: 宋体; mso-bidi-font-family: 宋体;\">用自動化的方式惡意使用本產品，給服務器造成過度的負擔或以其他方式干擾或損害本產品服務器和網絡鏈接； </span></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: 宋体; mso-bidi-font-family: 宋体;\">在未授權的情況下，嘗試訪問本產品的服務器數據或通信數據； </span></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: 宋体; mso-bidi-font-family: 宋体;\">干擾、破壞本產品其他用戶的使用； </span></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: normal; margin: 0cm 0cm 13.0pt 0cm;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: 宋体; mso-bidi-font-family: 宋体;\">未經本公司授權，修改、破解、反編譯、反匯編、逆向工程本產品，發佈本產品的修改版、破解版等； </span></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: 172%; margin: 0cm 0cm 13.0pt 0cm;\"><strong><span lang=\"ZH-TW\" style=\"font-size: 16.0pt; line-height: 172%; font-family: 宋体; mso-bidi-font-family: 宋体;\">4. 功能的調整、改進與升級 </span></strong></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: normal; margin: 0cm 0cm 13.0pt 0cm;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: 宋体; mso-bidi-font-family: 宋体;\">我們可能對產品進行不時地調整、改進和增減，甚至下線我們部分產品，以不斷適應我們的運營需要。任何本產品的更新版本或未來版本或者其他變更同樣受到本協議約束。 </span></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: 172%; margin: 0cm 0cm 13.0pt 0cm;\"><strong><span lang=\"ZH-TW\" style=\"font-size: 16.0pt; line-height: 172%; font-family: 宋体; mso-bidi-font-family: 宋体;\">5. 無擔保聲明 </span></strong></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: 宋体; mso-bidi-font-family: 宋体;\">5.1 本公司在發佈本產品之前，已盡可能對產品進行了詳盡的技術測試和功能測試，但鑒於電子設備、操作系統、網絡環境的複雜性，本公司不能保證本產品會兼容所有用戶的電子設備，也無法保證用戶在使用本產品過程中能夠持續不出現任何技術故障。</span></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: 宋体; mso-bidi-font-family: 宋体;\"><span style=\"mso-spacerun: yes;\">&nbsp;</span></span></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: 宋体; mso-bidi-font-family: 宋体;\">5.2 在法律允許的最大限度內，本公司無法對產品或服務做任何明示、暗示和強制的擔保，包括但不限於軟件的兼容性；產品一定滿足您的需求或期望；或產品將不間斷的、及時的、安全的、或無錯誤的運行。 </span></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: 宋体; mso-bidi-font-family: 宋体;\">&nbsp;</span></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: normal; margin: 0cm 0cm 13.0pt 0cm;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: 宋体; mso-bidi-font-family: 宋体;\">5.3 由於網絡環境的自由與開放特徵，我們的產品或服可能會被第三方擅自修改、破解發佈於互聯網，建議用戶從本公司的官方應用渠道，如官網、本公司已申請認證的第三方應用商店下載、安裝我們的產品，我們不會對任何非官方版本承擔任何責任。 </span></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: 172%; margin: 0cm 0cm 14.0pt 0cm;\"><strong><span lang=\"ZH-TW\" style=\"font-size: 16.0pt; line-height: 172%; font-family: 宋体; mso-bidi-font-family: 宋体;\">6. 賠償 </span></strong></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: 155%; margin: 0cm 0cm 14.5pt 0cm;\"><strong><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; line-height: 155%; font-family: 宋体; mso-bidi-font-family: 宋体;\">6.1 賠償</span></strong></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: normal; margin: 0cm 0cm 14.0pt 0cm;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: 宋体; mso-bidi-font-family: 宋体;\">在你違反本協議或你所提供的信息侵犯第三方合法權益而導致直接或間接損失的情況下，你應當賠償其他用戶、本公司、第三方合作夥伴的所有損失、費用或支出。 </span></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: 155%; margin: 0cm 0cm 14.5pt 0cm;\"><strong><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; line-height: 155%; font-family: 宋体; mso-bidi-font-family: 宋体;\">6.2 賠償程序</span></strong></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: normal; margin: 0cm 0cm 14.0pt 0cm;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: 宋体; mso-bidi-font-family: 宋体;\">可以通知你及時要求賠償。然而,本公司未能通知不會減輕你的賠償義務，除了在某種程度上，未能及時通知你給你造成了實質上的損害。 </span></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: 155%; margin: 0cm 0cm 14.5pt 0cm;\"><strong><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; line-height: 155%; font-family: 宋体; mso-bidi-font-family: 宋体;\">6.3 額外的責任</span></strong></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: normal; margin: 0cm 0cm 13.0pt 0cm;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: 宋体; mso-bidi-font-family: 宋体;\">你的賠償義務不是本公司的唯一補救措施，除此之外可能本公司對你依據本協議採取其他補救措施，你的賠償義務在本協議終止後仍存在。 </span></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: 172%; margin: 0cm 0cm 13.0pt 0cm;\"><strong><span lang=\"ZH-TW\" style=\"font-size: 16.0pt; line-height: 172%; font-family: 宋体; mso-bidi-font-family: 宋体;\">7. 不可抗力與責任限制 </span></strong></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; line-height: normal;\"><strong><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: 宋体; mso-bidi-font-family: 宋体; color: #303030;\">7.1 不可抗力：</span></strong><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: 宋体; mso-bidi-font-family: 宋体; color: #303030;\">本協議有效期間，如若遭受不可抗力事件，任何一方可暫行中止履行本協議項下的義務直至不可抗力事件的影響消除，並且遭受方無需為此承擔違約責任，但應及時將不可抗力事件及時通知對方，並盡最大努力克服該事件，減少損失的擴大。不可抗力指各方不能控制、不可預見或即使預見亦無法避免的事件且該事件足以妨礙、影響或延誤任何一方根據本協議履行其全部或部分義務。該事件包括但不限於自然災害、戰爭、法律法規變更、政府命令、計算機病毒、黑客攻擊或基礎電信運營商服務中斷等。 </span></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; line-height: normal;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: 宋体; mso-bidi-font-family: 宋体;\">&nbsp;</span></p>\r\n<p class=\"a\" style=\"line-height: normal; margin: 0cm 0cm 13.0pt 0cm;\"><strong><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: 宋体; mso-bidi-font-family: 宋体; color: #303030;\">7.2 損害限制：</span></strong><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: 宋体; mso-bidi-font-family: 宋体; color: #303030;\">本公司及其分支，和所屬的管理人員、董事、合伙人、僱員、承包商給你造成的所有損害賠償額度均僅限於你使用產品支付的款額。你放棄對特殊、間接、附帶或間接損害要求賠償的權利，包括並不限於利潤損失、收入、使用、或數據和應用的損失，即使本公司知道此類損失的可能性。</span></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: 172%; margin: 0cm 0cm 13.0pt 0cm;\"><strong><span lang=\"ZH-TW\" style=\"font-size: 16.0pt; line-height: 172%; font-family: 宋体; mso-bidi-font-family: 宋体;\">8. 個人信息保護 </span></strong></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: normal; margin: 0cm 0cm 13.0pt 0cm;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: 宋体; mso-bidi-font-family: 宋体;\">保護用戶跟個人信息安全、維護用戶隱私是我們一貫的理念，並且我們貫穿於所有產品或服務的立項、開發和運營過程。為不斷優化用戶體驗，向用戶提供更加個性化、智能化的內容與服務，我們會收集您的個人信息與非個人信息。您在使用特定的產品時，可以查看關於該產品的隱私說明以及我們的《隱私政策》，瞭解關於我們收集信息的內容、使用目的以及如何保護你的信息安全，該《產品隱私說明》和《隱私政策》均構成本協議的一部分。 </span></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: 172%; margin: 0cm 0cm 14.0pt 0cm;\"><strong><span lang=\"ZH-TW\" style=\"font-size: 16.0pt; line-height: 172%; font-family: 宋体; mso-bidi-font-family: 宋体;\">9. 其他 </span></strong></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: 155%; margin: 0cm 0cm 14.5pt 0cm;\"><strong><span lang=\"ZH-TW\" style=\"font-size: 14.0pt; line-height: 155%; font-family: 宋体; mso-bidi-font-family: 宋体;\">9.1 </span></strong><strong><span style=\"font-size: 14.0pt; line-height: 155%; font-family: 宋体; mso-bidi-font-family: 宋体; mso-ansi-language: ZH-CN; mso-fareast-language: ZH-CN;\">通知</span></strong></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: normal; margin: 0cm 0cm 14.0pt 0cm;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: 宋体; mso-bidi-font-family: 宋体;\">所有有關本協議以及隱私政策的疑問、通知、要求或請求,可以通過本公司郵箱聯繫：</span><span lang=\"EN-US\" style=\"font-size: 11.0pt; font-family: 宋体; mso-bidi-font-family: 宋体; mso-ansi-language: EN-US;\">support@lumoguide.com</span></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: 155%; margin: 0cm 0cm 14.5pt 0cm;\"><strong><span lang=\"ZH-TW\" style=\"font-size: 14.0pt; line-height: 155%; font-family: 宋体; mso-bidi-font-family: 宋体;\">9.2 本協議的修改</span></strong></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: normal; margin: 0cm 0cm 14.0pt 0cm;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: 宋体; mso-bidi-font-family: 宋体;\">由於業務的拓展、調整或法規變化等原因，本公司可能會適時修改本協議至被法律所允許的程度。如果調整會對您的權利與義務造成重大影響，我們會盡可能通過電子郵件、應用內通知等方式告知您。我們建議您定期訪查看我們的網站和移動應用程序，關注本協議的任何變化。在本協議修改後您繼續使用本產品代表您接受修改後的協議內容。 </span></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: 155%; margin: 0cm 0cm 14.5pt 0cm;\"><strong><span lang=\"ZH-TW\" style=\"font-size: 14.0pt; line-height: 155%; font-family: 宋体; mso-bidi-font-family: 宋体;\">9.3 適用法律和管轄法院</span></strong></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: normal; margin: 0cm 0cm 17.0pt 0cm;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: 宋体; mso-bidi-font-family: 宋体;\">執行本協議和所有程序引起的糾紛適用法律為奧地利聯邦共和國法律、解釋。由本協議引起的所有糾紛由我們附屬公司的住所地法院管轄。</span></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: normal; margin: 0cm 0cm 17.0pt 0cm;\">&nbsp;</p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: normal; margin: 0cm 0cm 17.0pt 0cm;\">English version</p>\r\n<div id=\"model-response-message-contentr_a4b3fa357ff5db66\" class=\"markdown markdown-main-panel stronger enable-updated-hr-color\" dir=\"ltr\" style=\"font-family: \'Google Sans Text\', sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\" aria-live=\"polite\" aria-busy=\"false\">\r\n<h1 style=\"font-family: \'Google Sans\', sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important; text-align: center;\" data-path-to-node=\"2\">User Agreement</h1>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">Overview</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">The Lumoguide User Agreement (hereinafter referred to as \"this Agreement\") applies to the products and services (hereinafter referred to as \"the Product\") operated and managed by the GUANPEI ZHOU Individual Enterprise (hereinafter referred to as \"we,\" \"us,\" or \"the Company\"). If a specific product or service has its own separate service rules, those rules shall take precedence. This Agreement is a legally binding legal agreement between you (either an individual or a single entity) and the Company regarding the use of the Product. This legal agreement includes, but is not limited to, all terms on this page as well as policies or service rules separately published by us for specific product features (if any).</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"4\"><strong style=\"line-height: 1.15 !important; margin-top: 0px !important;\">Please read the following terms carefully before using the Product. By downloading, installing, or using the Product, or by clicking \"I Agree,\" you acknowledge that you have read, fully understood, and agree to comply with all terms of this Agreement, including the disclaimer clauses involving the exemption or limitation of the Company\'s liability, terms restricting user rights, and the agreed-upon dispute resolution methods. These terms are highlighted in bold. If you do not agree with all or part of this Agreement, please do not download, install, or use the Product.</strong></p>\r\n<h3 style=\"font-family: \'Google Sans\', sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"5\">1. Statement of Rights</h3>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">1.1 Intellectual Property</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">The Company owns all rights, including ownership and intellectual property rights, in and to the Product. The Product is protected by the intellectual property laws of China and other countries, as well as international intellectual property conventions (including, but not limited to, copyright, trademark, and patent laws). All rights not expressly granted to you are reserved by the Company. You may not remove any copyright notices or other proprietary statements from the Product.</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">1.2 Reservation of Software Ownership</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">You expressly agree that you do not acquire ownership of the Software. The Software is licensed, not sold, to users, and the Company retains all ownership of the Software.</p>\r\n<h3 style=\"font-family: \'Google Sans\', sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"8\">2. Grant of License</h3>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">2.1 License Grant</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">The Company grants you a non-exclusive, non-transferable, non-commercial, and revocable license to download, install, back up, and use the Product. This license is granted solely for your personal, non-commercial use on mobile devices. If you intend to use the Product for any purpose not authorized by the Company or for commercial purposes, you must obtain separate written permission from the Company.</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">2.2 Restrictions</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">Unless otherwise expressly provided for certain third-party software or permitted by applicable law, you may not modify, translate, reverse assemble, reverse engineer, or decompile any part or all of the Software without the prior written consent of the Company.</p>\r\n<h3 style=\"font-family: \'Google Sans\', sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"11\">3. User Conduct</h3>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"12\">3.1 If you publish relevant user content while using the Company\'s products or services, you are solely responsible for all user content you publish. \"User Content\" refers to all content generated when you post or otherwise use the Product (e.g., your information, audio, images, or other content). You are the sole person responsible for your User Content and shall bear all legal liability arising from User Content that violates laws or infringes upon the rights of third parties.</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"13\"><strong style=\"line-height: 1.15 !important; margin-top: 0px !important;\">3.2 During use, you shall bear all legal responsibility arising from the following behaviors, and the Company assumes no responsibility for your actions:</strong></p>\r\n<ul style=\"padding-inline-start: 32px; line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"14\">\r\n<li style=\"line-height: 1.15 !important; margin-top: 0px !important;\">\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"14,0,0\"><strong style=\"line-height: 1.15 !important; margin-top: 0px !important;\">Undermining the basic principles established by the Constitution;</strong></p>\r\n</li>\r\n<li style=\"line-height: 1.15 !important; margin-top: 0px !important;\">\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"14,1,0\"><strong style=\"line-height: 1.15 !important; margin-top: 0px !important;\">Endangering national security, leaking state secrets, subverting state power, or undermining national unity;</strong></p>\r\n</li>\r\n<li style=\"line-height: 1.15 !important; margin-top: 0px !important;\">\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"14,2,0\"><strong style=\"line-height: 1.15 !important; margin-top: 0px !important;\">Damaging national honor and interests;</strong></p>\r\n</li>\r\n<li style=\"line-height: 1.15 !important; margin-top: 0px !important;\">\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"14,3,0\"><strong style=\"line-height: 1.15 !important; margin-top: 0px !important;\">Inciting ethnic hatred or discrimination, or undermining ethnic solidarity;</strong></p>\r\n</li>\r\n<li style=\"line-height: 1.15 !important; margin-top: 0px !important;\">\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"14,4,0\"><strong style=\"line-height: 1.15 !important; margin-top: 0px !important;\">Violating national religious policies or promoting cults and feudal superstitions;</strong></p>\r\n</li>\r\n<li style=\"line-height: 1.15 !important; margin-top: 0px !important;\">\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"14,5,0\"><strong style=\"line-height: 1.15 !important; margin-top: 0px !important;\">Spreading rumors, disrupting social order, or undermining social stability;</strong></p>\r\n</li>\r\n<li style=\"line-height: 1.15 !important; margin-top: 0px !important;\">\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"14,6,0\"><strong style=\"line-height: 1.15 !important; margin-top: 0px !important;\">Spreading obscenity, pornography, gambling, violence, murder, terror, or inciting crime;</strong></p>\r\n</li>\r\n<li style=\"line-height: 1.15 !important; margin-top: 0px !important;\">\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"14,7,0\"><strong style=\"line-height: 1.15 !important; margin-top: 0px !important;\">Insulting or slandering others, or infringing upon the legitimate rights and interests of others;</strong></p>\r\n</li>\r\n<li style=\"line-height: 1.15 !important; margin-top: 0px !important;\">\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"14,8,0\"><strong style=\"line-height: 1.15 !important; margin-top: 0px !important;\">Containing other content prohibited by laws and administrative regulations.</strong></p>\r\n</li>\r\n</ul>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"15\">3.3 You agree not to engage in the following activities through the Product:</p>\r\n<ul style=\"padding-inline-start: 32px; line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"16\">\r\n<li style=\"line-height: 1.15 !important; margin-top: 0px !important;\">\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"16,0,0\">Publishing or sharing computer viruses, worms, malicious code, or software intended to destroy or alter computer systems or data;</p>\r\n</li>\r\n<li style=\"line-height: 1.15 !important; margin-top: 0px !important;\">\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"16,1,0\">Unauthorized collection of information or data of other users, such as illegal collection of personal information of third parties that infringes on their privacy or other legitimate civil rights;</p>\r\n</li>\r\n<li style=\"line-height: 1.15 !important; margin-top: 0px !important;\">\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"16,2,0\">Maliciously using the Product via automated means, imposing an excessive burden on servers, or otherwise interfering with or damaging the Product\'s servers and network links;</p>\r\n</li>\r\n<li style=\"line-height: 1.15 !important; margin-top: 0px !important;\">\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"16,3,0\">Attempting to access the Product\'s server data or communication data without authorization;</p>\r\n</li>\r\n<li style=\"line-height: 1.15 !important; margin-top: 0px !important;\">\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"16,4,0\">Interfering with or disrupting the use of the Product by other users;</p>\r\n</li>\r\n<li style=\"line-height: 1.15 !important; margin-top: 0px !important;\">\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"16,5,0\">Modifying, cracking, decompiling, disassembling, or reverse engineering the Product without the Company\'s authorization, or publishing modified or cracked versions of the Product.</p>\r\n</li>\r\n</ul>\r\n<h3 style=\"font-family: \'Google Sans\', sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"17\">4. Adjustment, Improvement, and Upgrade of Functions</h3>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"18\">We may from time to time adjust, improve, add to, or remove features, or even discontinue certain products to adapt to our operational needs. Any updated versions, future versions, or other changes to the Product shall likewise be governed by this Agreement.</p>\r\n<h3 style=\"font-family: \'Google Sans\', sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"19\">5. Disclaimer of Warranties</h3>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"20\"><strong style=\"line-height: 1.15 !important; margin-top: 0px !important;\">5.1 The Company has conducted extensive technical and functional testing of the Product prior to its release. However, given the complexity of electronic devices, operating systems, and network environments, the Company cannot guarantee that the Product will be compatible with all users\' electronic devices, nor can it guarantee that no technical failures will occur during use.</strong></p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"21\"><strong style=\"line-height: 1.15 !important; margin-top: 0px !important;\">5.2 To the maximum extent permitted by law, the Company makes no express, implied, or statutory warranties regarding the Product or services, including but not limited to software compatibility; that the Product will meet your needs or expectations; or that the Product will operate uninterrupted, timely, secure, or error-free.</strong></p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"22\"><strong style=\"line-height: 1.15 !important; margin-top: 0px !important;\">5.3 Due to the free and open nature of the network environment, our products or services may be unauthorizedly modified or cracked by third parties and published on the Internet. Users are advised to download and install our products through the Company\'s official channels (e.g., official website, certified third-party app stores). We assume no responsibility for any unofficial versions.</strong></p>\r\n<h3 style=\"font-family: \'Google Sans\', sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"23\">6. Indemnification</h3>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">6.1 Indemnity</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">In the event that your violation of this Agreement or the information you provide infringes upon the legitimate rights of a third party, resulting in direct or indirect losses, you shall indemnify other users, the Company, and third-party partners for all losses, costs, or expenses incurred.</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">6.2 Indemnification Procedure</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">The Company may notify you to promptly demand indemnification. However, any failure by the Company to provide such notice shall not relieve you of your indemnification obligations, except to the extent that such failure causes you material prejudice.</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">6.3 Additional Liability</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">Your indemnification obligation is not the Company\'s sole remedy. The Company may take other remedial measures against you in accordance with this Agreement. Your indemnification obligation shall survive the termination of this Agreement.</p>\r\n<h3 style=\"font-family: \'Google Sans\', sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">7. Force Majeure and Limitation of Liability</h3>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"28\"><strong style=\"line-height: 1.15 !important; margin-top: 0px !important;\">7.1 Force Majeure:</strong>&nbsp;During the term of this Agreement, if a force majeure event occurs, either party may temporarily suspend the performance of its obligations hereunder until the impact of the force majeure event is eliminated. The affected party shall not be liable for breach of contract but shall promptly notify the other party and use its best efforts to overcome the event and mitigate losses. Force majeure refers to events beyond the control of the parties, which are unforeseeable, or if foreseeable, unavoidable, and which are sufficient to prevent, affect, or delay any party\'s performance of all or part of its obligations under this Agreement. Such events include, but are not limited to, natural disasters, war, changes in laws and regulations, government orders, computer viruses, hacker attacks, or service interruptions by basic telecommunications operators.</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"29\"><strong style=\"line-height: 1.15 !important; margin-top: 0px !important;\">7.2 Limitation of Damages: The total liability of the Company and its branches, officers, directors, partners, employees, and contractors for all damages caused to you shall be limited to the amount you paid to use the Product. You waive the right to claim compensation for special, indirect, incidental, or consequential damages, including but not limited to loss of profits, revenue, use, or data and applications, even if the Company was aware of the possibility of such losses.</strong></p>\r\n<h3 style=\"font-family: \'Google Sans\', sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"30\">8. Protection of Personal Information</h3>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"31\">Protecting user personal information security and maintaining user privacy is our consistent philosophy, which we integrate into the planning, development, and operation of all products and services. To continuously optimize user experience and provide more personalized and intelligent content and services, we collect your personal and non-personal information. When using specific products, you can view the privacy statement for that product and our \"Privacy Policy\" to understand the information we collect, the purpose of its use, and how we protect your information security. The \"Product Privacy Statement\" and \"Privacy Policy\" both constitute an integral part of this Agreement.</p>\r\n<h3 style=\"font-family: \'Google Sans\', sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"32\">9. Miscellaneous</h3>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">9.1 Notifications</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">All inquiries, notices, requirements, or requests regarding this Agreement and the Privacy Policy may be directed to the Company via email at: support@lumoguide.com</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">9.2 Amendments to this Agreement</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">Due to business expansion, adjustments, or changes in regulations, the Company may modify this Agreement from time to time to the extent permitted by law. If such adjustments significantly affect your rights and obligations, we will endeavor to inform you via email, in-app notifications, etc. We recommend that you regularly check our website and mobile application for any changes to this Agreement. Your continued use of the Product after the modification of this Agreement signifies your acceptance of the revised content.</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">9.3 Governing Law and Jurisdiction</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">The execution of this Agreement and the resolution of disputes arising from all procedures shall be governed by and construed in accordance with the laws of the Republic of Austria. All disputes arising from this Agreement shall be subject to the jurisdiction of the courts located at the place of residence of our affiliated company.</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">简体字版：</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important; text-align: center;\"><span style=\"font-size: 18pt;\">《用户协议》</span></p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">&nbsp;</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">概述</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">路盟（Lumoguide）用户协议（以下简称「本协议」）适用于 GUANPEI ZHOU 个人公司运营和管理（以下简称「我们」，「本公司」）旗下的产品与服务（以下简称「本产品」），如果某项产品与服务有单独的服务规则，则该产品的服务规则优先适用。本协议是您（个人或单一实体）与本公司之间就使用本产品达成的具有法律 约束力的法律协议。该法律协议包括但不限于本页面的全部条款以及我们针对特定产品部分功能单独发布的政策或服务规则等（若有）。</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">&nbsp;</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">请您在使用本产品之前仔细阅读下列条款。您下载、安装或使用产本品或者单击「 我同意」表明您已经阅读本协议并充分理解、遵守本协议所有条款，包括涉及免除或者限制本公司责任的免责条款、用户权利限制条款、约定争议解决方式等，这些条款均用粗体字标注。如果您不同意本协议的全部或部分内容，请不要下载、安装和使用本产品。</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">&nbsp;</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">1. 权利声明</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">1.1 知识产权</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">本公司拥有「本产品」的所有权和知识产权等全部权利。本产品受中国及其他国家的知识产权法、国际知识产权 公约（包括但不限于著作权法、商标法、专利法等）的保护。所有未授予您的权利均被本公司保留，您不可以从本产品上移除本公司的版权标记或其他权利声明。</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">&nbsp;</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">1.2 软件所有权保留</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">您确定不享有本软件的所有权，本软件未被出售给用户，本公司保留本软件的所有权。</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">&nbsp;</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">2. 授权许可</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">2.1 授权许可</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">本公司授予您一项非排他的、不可转让的、非商业性的、可撤销的许可，以下载、安装、备份和使用本产品。本公司授予您仅出于个人非商业目在移动设备上使用本产品，如果您希望将本产品用于其他非本公司授权的目的或其他商业目的，您必须另行取得本公​​司的单独书面许可。</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">&nbsp;</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">2.2 限制</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">除非就某些第三方软件软件有明文规定或适用法律允许，否则您不得在未取得本公司书面许可的情况下修改、翻译、反向汇编、反向工程、反编译本软件的部分或全部。</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">&nbsp;</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">3. 用户行为</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">3.1 如果您在使用本公司产品或服务的过程中发布相关用户内容，您需要对自己发布的所有用户内容负责。用户 内容是指您发布或以其他方式使用本产品时产生的所有内容（例如：您的信息、声音、图片或其他内容）。您是您的用户内容唯一的责任人，您将承担因您的用户内容违法法律、侵犯第三方权益的所有法律责任。</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">3.2 在使用过程中，您将承担因下述行为而产生的全部法律责任，本公司不对您的下述行为承担任何责任：</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">破坏宪法所确定的基本原则的；</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">危害国家安全、泄露国家秘密、颠覆国家政权、破坏国家统一的；</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">损害国家荣誉和利益的；</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">煽动民族仇恨、民族歧视，破坏民族团结的；</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">破坏国家宗教政策，宣扬邪教和封建迷信的；</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">散布谣言，扰乱社会秩序，破坏社会稳定的；</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">散布淫秽、色情、赌博、暴力、凶杀、恐怖或者教唆犯罪的；</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">侮辱或者诽谤他人，侵害他人合法权益的；</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">含有法律、行政法规禁止的其他内容的。</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">&nbsp;</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">3.3 您同意不通过本产品从事下列行为：</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">发布或分享电脑病毒、蠕虫、恶意代码、故意破坏或改变计算机系统或数据的软件；</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">未经授权，收集其他用户的信息或数据，例如非法收集第三人的个人信息侵犯第三人隐私或其他合法民事权益；</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">用自动化的方式恶意使用本产品，给服务器造成过度的负担或以其他方式干扰或损害本产品服务器和网络链接；</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">在未授权的情况下，尝试访问本产品的服务器数据或通信数据；</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">干扰、破坏本产品其他用户的使用；</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">未经本公司授权，修改、破解、反编译、反汇编、逆向工程本产品，发布本产品的修改版、破解版等；</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">&nbsp;</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">4. 功能的调整、改进与升级</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">我们可能对产品进行不时地调整、改进和增减，甚至下线我们部分产品，以不断适应我们的运营需要。任何本产品的更新版本或未来版本或者其他变更同样受到本协议约束。</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">&nbsp;</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">5. 无担保声明</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">5.1 本公司在发布本产品之前，已尽可能对产品进行了详尽的技术测试和功能测试，但鉴于电子设备、操作系统、网络环境的复杂性，本公司不能保证本产品会兼容所有用户的电子设备，也无法保证用户在使用本产品过程中能够持续不出现任何技术故障。</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">5.2 在法律允许的最大限度内，本公司无法对产品或服务做任何明示、暗示和强制的担保，包括但不限于软件的兼容性；产品一定满足您的需求或期望；或产品将不间断的、及时的、安全的、或无错误的运行。</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">5.3 由于网络环境的自由与开放特征，我们的产品或服可能会被第三方擅自修改、破解发布于互联网，建议用户从本公司的官方应用渠道，如官网、本公司已申请认证的第三方应用商店下载、安装我们的产品，我们不会对任何非官方版本承担任何责任。</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">&nbsp;</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">6. 赔偿</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">6.1 赔偿</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">在你违反本协议或你所提供的信息侵犯第三方合法权益而导致直接或间接损失的情况下，你应当赔偿其他用户、本公司、第三方合作伙伴的所有损失、费用或支出。</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">6.2 赔偿程序</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">可以通知你及时要求赔偿。然而,本公司未能通知不会减轻你的赔偿义务，除了在某种程度上，未能及时通知你给你造成了实质上的损害。</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">6.3 额外的责任</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">你的赔偿义务不是本公司的唯一补救措施，除此之外可能本公司对你依据本协议采取其他补救措施，你的赔偿义务在本协议终止后仍存在。</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">&nbsp;</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">7. 不可抗力与责任限制</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">7.1 不可抗力：本协议有效期间，如若遭受不可抗力事件，任何一方可暂行中止履行本协议项下的义务直至不可抗力事件的影响消除，并且遭受方无需为此承担违约责任，但应及时将不可抗力事件及时通知对方，并尽最大努力克服该事件，减少损失的扩大。不可抗力指各方不能控制、不可预见或即使预见亦无法避免的事件且该事件足以妨碍、影响或延误任何一方根据本协议履行其全部或部分义务。该事件包括但不限于自然灾害、战争、法律法规变更、政府命令、计算机病毒、黑客攻击或基础电信运营商服务中断等。</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">7.2 损害限制：本公司及其分支，和所属的管理人员、董事、合伙人、雇员、承包商给你造成的所有损害赔偿额度均仅限于你使用产品支付的款额。你放弃对特殊、间接、附带或间接损害要求赔偿的权利，包括并不限于利润损失、收入、使用、或数据和应用的损失，即使本公司知道此类损失的可能性。</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">&nbsp;</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">8. 个人信息保护</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">保护用户跟个人信息安全、维护用户隐私是我们一贯的理念，并且我们贯穿于所有产品或服务的立项、开发和运营过程。为不断优化用户体验，向用户提供更加个性化、智能化的内容与服务，我们会收集您的个人信息与非个人信息。您在使用特定的产品时，可以查看关于该产品的隐私说明以及我们的《隐私政策》，了解关于我们收集信息的内容、使用目的以及如何保护你的信息安全，该《产品隐私说明》和《隐私政策》均构成本协议的一部分。</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">&nbsp;</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">9. 其他</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">9.1 通知</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">所有有关本协议以及隐私政策的疑问、通知、要求或请求,可以通过本公司邮箱联系：support@lumoguide.com</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">9.2 本协议的修改</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">由于业务的拓展、调整或法规变化等原因，本公司可能会适时修改本协议至被法律所允许的程度。如果调整会对您的权利与义务造成重大影响，我们会尽可能通过电子邮件、应用内通知等方式告知您。我们建议您定期访查看我们的网站和移动应用程序，关注本协议的任何变化。在本协议修改后您继续使用本产品代表您接受修改后的协议内容。</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">9.3 适用法律和管辖法院</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">执行本协议和所有程序引起的纠纷适用法律为奥地利联邦共和国法律、解释。由本协议引起的所有纠纷由我们附属公司的住所地法院管辖。</p>\r\n</div>','2025-06-16 19:51:25','2025-12-21 01:37:24'),(2,'隱私協議',2,'privacy_protocol','<p class=\"a\" style=\"text-align: center; line-height: 240%; margin: 0cm 0cm 16.5pt 0cm;\" align=\"center\"><span style=\"font-size: 22.0pt; line-height: 240%; font-family: \'PingFang SC Semibold\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Semibold\'; mso-hansi-font-family: \'Arial Unicode MS\';\">《</span><span style=\"font-size: 22.0pt; line-height: 240%; font-family: \'PingFang SC Semibold\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Semibold\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-CN;\">路盟</span><span lang=\"ZH-TW\" style=\"font-size: 22.0pt; line-height: 240%; font-family: \'PingFang SC Semibold\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Semibold\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">產品隱私政策》</span></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Regular\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">本款產品由</span><span lang=\"EN-US\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\">LUMOGUIDE</span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'PingFang TC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">（以下簡稱「</span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Regular\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">我們</span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'PingFang TC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">」）提供。我們深知個人信息對用戶的重要性，也深知為用戶的個人信息提供有效保護是我們業務健康可持續發展的基石。感謝您對我們產品和服務的使用和信任！我們鄭重承諾，我們將按業界成熟的安全標準，採取相應的安全保護措施來保護您的個人信息。我們希望通過本隱私政策向您說明，在使用我們的產品和服務時，我們如何收集、使用、存儲、分享和轉讓您的個人信息，以及我們為您提供的訪問、更新、刪除和保護這些信息的方式。</span></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"EN-US\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif; mso-fareast-font-family: Helvetica; mso-bidi-font-family: Helvetica;\">&nbsp;</span></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Regular\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">請在使用我們的產品和服務前，務必仔細閱讀並瞭解本隱私政策，在確認充分理解並同意後使用我們的產品或服務。一旦您開始使用我們的產品和服務，即表示您已充分理解並同意本政策，並同意我們按照本隱私政策收集、使用、儲存和分享您的相關信息。如對本政策內容有任何疑問、意見或建議，您可通過本隱私政策提供的各種聯繫方式與我們聯繫。</span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\"> </span></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: normal; margin: 0cm 0cm 13.0pt 0cm;\"><span lang=\"EN-US\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif; mso-fareast-font-family: Helvetica; mso-bidi-font-family: Helvetica;\">&nbsp;</span></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: 172%; margin: 0cm 0cm 13.0pt 0cm;\"><span style=\"font-size: 16.0pt; line-height: 172%; font-family: \'PingFang SC Semibold\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Semibold\'; mso-hansi-font-family: \'Arial Unicode MS\';\">一</span><strong><span lang=\"EN-US\" style=\"font-size: 16.0pt; line-height: 172%; font-family: \'Helvetica\',serif;\">.</span></strong><span lang=\"ZH-TW\" style=\"font-size: 16.0pt; line-height: 172%; font-family: \'PingFang SC Semibold\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Semibold\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">獲取權限說明</span></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"EN-US\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\">1.</span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Regular\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">獲取存儲權限，設備授權，動態獲取，需要用戶授權。用戶基礎的軟件使用。</span></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"EN-US\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\">2.</span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Regular\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">電話權限，動態獲取，需要用戶授權。讀取電話狀態（設備</span><span lang=\"EN-US\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\">IMSI/IMEI</span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Regular\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">號）用於展示驗機手機配置中</span><span lang=\"EN-US\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\">IMEI</span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Regular\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">號字段內容；用於用戶身份識別（使用中我們會將</span><span lang=\"EN-US\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\">IMEI</span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Regular\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">進行加密），賬號安全，業務安全等需要；獲取設備識別碼用於權限用戶的確認等。</span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\"> </span></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"EN-US\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\">3.</span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Regular\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">通知讀取和展示權限，動態獲取，需要用戶授權。用於通知欄清理功能。</span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\"> </span></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"EN-US\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\">4.</span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Regular\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">相機拍攝權限，動態獲取，需要用戶授權。用於完成手機檢測時檢測相機相關功能是否正常。</span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\"> </span></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"EN-US\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\">5.</span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Regular\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">位置權限，動態獲取，需要用戶授權。粗略獲取位置，功能使用統計等功能；</span></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"EN-US\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\">6.</span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Regular\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">自啓動權限，動態獲取，需要用戶授權。用於通知欄清理等功能。</span><span lang=\"EN-US\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\">&nbsp; </span></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"EN-US\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\">7.</span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Regular\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">錄音權限，動態獲取，需要用戶授權。用於基本音視頻通話使用。</span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\"> </span></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: normal; margin: 0cm 0cm 13.0pt 0cm;\"><span lang=\"EN-US\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif; mso-fareast-font-family: Helvetica; mso-bidi-font-family: Helvetica;\">&nbsp;</span></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: 172%; margin: 0cm 0cm 14.0pt 0cm;\"><span style=\"font-size: 16.0pt; line-height: 172%; font-family: \'PingFang SC Semibold\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Semibold\'; mso-hansi-font-family: \'Arial Unicode MS\';\">二</span><strong><span lang=\"EN-US\" style=\"font-size: 16.0pt; line-height: 172%; font-family: \'Helvetica\',serif;\">.</span></strong><span lang=\"ZH-TW\" style=\"font-size: 16.0pt; line-height: 172%; font-family: \'PingFang SC Semibold\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Semibold\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">管理個人信息的權利</span></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: 155%; margin: 0cm 0cm 14.5pt 0cm;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; line-height: 155%; font-family: \'PingFang TC Semibold\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang TC Semibold\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">（一）訪問和更正您的個人信息</span><strong><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; line-height: 155%; font-family: \'Helvetica\',serif;\"> </span></strong></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Regular\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">您有權訪問您的個人信息，法律法規規定的例外情況除外。您可以隨時使用我們的</span><span lang=\"EN-US\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\"> Web </span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Regular\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">表單聯繫入口在【我的】</span><span lang=\"EN-US\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif;\">&rarr;</span><span lang=\"JA\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Regular\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: JA; mso-fareast-language: JA;\">【設置】</span><span lang=\"EN-US\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif;\">&rarr;</span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Regular\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">【反饋】我們將在</span><span lang=\"EN-US\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\">15</span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Regular\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">天內回復您的訪問請求。</span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\"> </span></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: normal; margin: 0cm 0cm 14.0pt 0cm;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Regular\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">對於您在使用我們的產品或服務過程中產生的其他個人信息，只要我們不需要過多投入，我們會向您提供。</span></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: 155%; margin: 0cm 0cm 14.5pt 0cm;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; line-height: 155%; font-family: \'PingFang TC Semibold\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang TC Semibold\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">（二）刪除您的個人信息</span><strong><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; line-height: 155%; font-family: \'Helvetica\',serif;\"> </span></strong></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Regular\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">以下情況發生時，您有權要求我們刪除您的個人信息：</span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\"> </span></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"EN-US\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\">1. </span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Regular\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">我們沒有徵求您的明確同意，收集了您的個人信息。</span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\"> </span></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"EN-US\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\">2. </span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Regular\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">我們處理您的個人信息違反了法律法規要求。</span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\"> </span></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"EN-US\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\">3. </span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Regular\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">我們違反了與您的約定來使用和處理您的個人信息。</span></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"EN-US\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\">4. </span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Regular\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">您註銷了賬號、卸載或者不再使用我們的產品（或服務）。</span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\"> </span></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"EN-US\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\">5. </span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Regular\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">我們停止對您提供服務。</span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\"> </span></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: normal; margin: 0cm 0cm 14.0pt 0cm;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Regular\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">您可以通過本隱私政策提供的方式聯繫我們要求刪除您的個人信息。</span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif; color: #303030;\"> </span></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: 155%; margin: 0cm 0cm 14.5pt 0cm;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; line-height: 155%; font-family: \'PingFang TC Semibold\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang TC Semibold\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">（三）註銷您的個人賬戶</span><strong><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; line-height: 155%; font-family: \'Helvetica\',serif;\"> </span></strong></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Regular\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">您隨時可註銷此前註冊的賬戶，您可以通過以下方式自行操作：操作路徑為【我的】</span><span lang=\"EN-US\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif;\">&rarr;</span><span lang=\"JA\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Regular\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: JA; mso-fareast-language: JA;\">【設置】</span><span lang=\"EN-US\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif;\">&rarr;</span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Regular\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">【賬號管理】</span><span lang=\"EN-US\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif;\">&rarr;</span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Regular\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">【賬號註銷】進行操作。</span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\"> </span></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: normal; margin: 0cm 0cm 14.0pt 0cm;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Regular\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">在註銷賬戶之後，我們將停止為您提供產品或服務，並依據您的要求，刪除您的個人信息，法律法規另有規定的除外。這些一旦刪除將不可以恢復，因此請您理解，在您提交申請後，為保障賬號安全，我們可能需要驗證您的身份後再進行人工審核和確認。</span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif; color: #303030;\"> </span></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: 155%; margin: 0cm 0cm 14.5pt 0cm;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; line-height: 155%; font-family: \'PingFang TC Semibold\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang TC Semibold\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">（四）撤回您的同意或授權</span><strong><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; line-height: 155%; font-family: \'Helvetica\',serif;\"> </span></strong></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"EN-US\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\">1. </span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Regular\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">每個業務功能需要一些基本的個人信息才能得以完成。對於額外收集的個人信息的收集和使用，您可以隨時給予或收回您的授權同意。</span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\"> </span></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"EN-US\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\">2. </span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Regular\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">您可以通過以下方式自行操作：通過手機系統設置調整對</span><span lang=\"ES-TRAD\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif; mso-ansi-language: ES-TRAD;\">APP</span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Regular\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">的授權。</span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\"> </span></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: normal; margin: 0cm 0cm 14.0pt 0cm;\"><span lang=\"EN-US\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\">3. </span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Regular\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">當您收回同意後，我們將不再處理相應的個人信息。但您收回同意的決定，不會影響此前基於您的授權而開展的個人信息處理。</span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\"> </span></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: 155%; margin: 0cm 0cm 14.5pt 0cm;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; line-height: 155%; font-family: \'PingFang TC Semibold\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang TC Semibold\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">（五）響應您的上述請求</span><strong><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; line-height: 155%; font-family: \'Helvetica\',serif;\"> </span></strong></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: normal; margin: 0cm 0cm 13.0pt 0cm;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Regular\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">為保障安全，您可能需要提供書面請求，或以其他方式證明您的身份。我們可能會先要求您驗證自己的身份，然後再處理您的請求。但請您理解，基於法律法規要求、保障信息安全、技術限制等原因，您的部分信息可能無法訪問、修改和刪除。</span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\"> </span></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: 172%; margin: 0cm 0cm 13.0pt 0cm;\"><span style=\"font-size: 16.0pt; line-height: 172%; font-family: \'PingFang SC Semibold\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Semibold\'; mso-hansi-font-family: \'Arial Unicode MS\';\">三</span><strong><span lang=\"EN-US\" style=\"font-size: 16.0pt; line-height: 172%; font-family: \'Helvetica\',serif;\">.</span></strong><span lang=\"ZH-TW\" style=\"font-size: 16.0pt; line-height: 172%; font-family: \'PingFang SC Semibold\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Semibold\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">未成年人個人信息保護</span><strong><span lang=\"ZH-TW\" style=\"font-size: 16.0pt; line-height: 172%; font-family: \'Helvetica\',serif;\"> </span></strong></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Regular\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">若您是</span><span lang=\"EN-US\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\">18</span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Regular\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">週歲以下的未成年人，在使用我們的產品和服務前，應事先取得您的家長或法定監護人的同意。</span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\"> </span></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: normal; margin: 0cm 0cm 13.0pt 0cm;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Regular\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">若您是未滿</span><span lang=\"EN-US\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\">14</span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Regular\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">週歲的兒童，須在監護人的陪同下閱讀本隱私政策或相應產品或服務的隱私政策，決定是否使用我們的產品或服務。如獲得產品和服務需要提交個人信息，請取得監護人的同意，並在監護人的指導下完成。若您是兒童的監護人，當您在幫助兒童完成產品或服務的註冊、使用前，應當仔細閱讀本政策或特定產品的隱私保護政策，決定是否同意隱私政策。當您對您所監護的兒童的個人信息有疑問時，您可以通過本隱私政策第九節的聯繫方式與我們聯繫。</span></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: 172%; margin: 0cm 0cm 13.0pt 0cm;\"><span style=\"font-size: 16.0pt; line-height: 172%; font-family: \'PingFang SC Semibold\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Semibold\'; mso-hansi-font-family: \'Arial Unicode MS\';\">四</span><strong><span lang=\"EN-US\" style=\"font-size: 16.0pt; line-height: 172%; font-family: \'Helvetica\',serif;\">.</span></strong><span lang=\"ZH-TW\" style=\"font-size: 16.0pt; line-height: 172%; font-family: \'PingFang SC Semibold\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Semibold\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">隱私政策的適用範圍</span><strong><span lang=\"ZH-TW\" style=\"font-size: 16.0pt; line-height: 172%; font-family: \'Helvetica\',serif;\"> </span></strong></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Regular\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">本私政策僅適用於安卓版、</span><span lang=\"EN-US\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\">IOS</span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Regular\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">版。我們的其他產品和服務將使用相關產品或服務的隱私政策。特別需要說明的是，本隱私政策不適用以下情況：</span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\"> </span></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"EN-US\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\">1. </span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Regular\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">將我們的產品（或服務）嵌入到第三方產品（或服務），第三方產品（或服務）收集的信息。</span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\"> </span></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"EN-US\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\">2. </span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Regular\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">在我們的產品（或服務）中接入的第三方服務、廣告或其他公司、組織或個人所收集的信息。</span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\"> </span></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: normal; margin: 0cm 0cm 14.0pt 0cm;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Regular\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">我們在此提醒您，您在使用第三方產品與</span><span lang=\"EN-US\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\">/</span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Regular\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">或服務時，請仔細閱讀第三方向您展示的相關用戶協議和隱私政策，並妥善保管和謹慎提供您的個人信息。</span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\"> </span></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: 155%; margin: 0cm 0cm 14.5pt 0cm;\"><span style=\"font-size: 14.0pt; line-height: 155%; font-family: \'PingFang SC Semibold\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Semibold\'; mso-hansi-font-family: \'Arial Unicode MS\';\">五</span><strong><span lang=\"EN-US\" style=\"font-size: 14.0pt; line-height: 155%; font-family: \'Helvetica\',serif;\">.</span></strong><span lang=\"ZH-TW\" style=\"font-size: 14.0pt; line-height: 155%; font-family: \'PingFang SC Semibold\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Semibold\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">隱私政策的變更和修訂</span><strong><span lang=\"ZH-TW\" style=\"font-size: 14.0pt; line-height: 155%; font-family: \'Helvetica\',serif;\"> </span></strong></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Regular\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">我們的隱私政策可能變更。未經您明確同意，我們不會限制您按照本隱私政策所應享有的權利。對於本隱私政策的重大變更，我們還會提供顯著的通知（例如，在軟件改版或升級、或您重新登錄時，以彈窗形式對您進行及時通知）。</span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\"> </span></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Regular\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">本政策所指的重大變更包括但不限於：</span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\"> </span></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"EN-US\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\">1. </span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Regular\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">我們的服務模式發生重大變化。如處理個人信息的目的、處理的個人信息類型、個人信息的使用方式等；</span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\"> </span></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"EN-US\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\">2. </span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Regular\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">我們在控制權等方面發生重大變化。如並購重組等引起的所有者變更等；</span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\"> </span></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"EN-US\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\">3. </span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Regular\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">個人信息共享、轉讓或公開披露的主要對象發生變化；</span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\"> </span></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"EN-US\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\">4. </span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Regular\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">您參與個人信息處理方面的權利及其行使方式發生重大變化；</span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\"> </span></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"EN-US\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\">5. </span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Regular\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">我們負責處理個人信息安全的責任部門、聯絡方式及投訴渠道發生變化時；</span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\"> </span></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: normal; margin: 0cm 0cm 13.0pt 0cm;\"><span lang=\"EN-US\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\">6. </span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Regular\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">個人信息安全影響評估報告表明存在高風險時。</span><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\"> </span></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: 172%; margin: 0cm 0cm 13.0pt 0cm;\"><span lang=\"JA\" style=\"font-size: 16.0pt; line-height: 172%; font-family: \'PingFang SC Semibold\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Semibold\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: JA; mso-fareast-language: JA;\">六</span><strong><span lang=\"EN-US\" style=\"font-size: 16.0pt; line-height: 172%; font-family: \'Helvetica\',serif;\">.</span></strong><span lang=\"ZH-TW\" style=\"font-size: 16.0pt; line-height: 172%; font-family: \'PingFang SC Semibold\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Semibold\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">如何聯繫我們</span><strong><span lang=\"ZH-TW\" style=\"font-size: 16.0pt; line-height: 172%; font-family: \'Helvetica\',serif;\"> </span></strong></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"ZH-TW\" style=\"font-size: 11.0pt; font-family: \'PingFang SC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Regular\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">如果您對我們的隱私政策及對您個人信息的處理有任何疑問、意見、建議或投訴，請通過以下方式與我們聯繫，</span><span lang=\"EN-US\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\"> Email</span><span style=\"font-size: 11.0pt; font-family: \'PingFang TC Regular\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-hansi-font-family: \'Arial Unicode MS\';\">：</span><span lang=\"EN-US\" style=\"font-size: 11.0pt; font-family: \'Helvetica\',serif;\">support@lumoguide.com</span></p>\r\n<p class=\"a\" style=\"margin-top: 0cm; text-align: justify; text-justify: inter-ideograph; line-height: normal;\"><span lang=\"EN-US\" style=\"font-size: 10.5pt; font-family: \'Helvetica\',serif; mso-fareast-font-family: Helvetica; mso-bidi-font-family: Helvetica;\">&nbsp;</span></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: normal; margin: 0cm 0cm 13.0pt 0cm;\"><span lang=\"EN-US\" style=\"font-size: 10.5pt; font-family: \'Helvetica\',serif; mso-fareast-font-family: Helvetica; mso-bidi-font-family: Helvetica;\">&nbsp;</span></p>\r\n<p class=\"a\" style=\"text-align: justify; text-justify: inter-ideograph; line-height: 172%; margin: 0cm 0cm 13.0pt 0cm;\"><span lang=\"ZH-TW\" style=\"font-size: 16.0pt; line-height: 172%; font-family: \'PingFang SC Semibold\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Semibold\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">七</span><strong><span lang=\"EN-US\" style=\"font-size: 16.0pt; line-height: 172%; font-family: \'Helvetica\',serif;\">.</span></strong><span lang=\"ZH-TW\" style=\"font-size: 16.0pt; line-height: 172%; font-family: \'PingFang SC Semibold\',serif; mso-ascii-font-family: \'Arial Unicode MS\'; mso-fareast-font-family: \'PingFang SC Semibold\'; mso-hansi-font-family: \'Arial Unicode MS\'; mso-ansi-language: ZH-TW; mso-fareast-language: ZH-TW;\">隱私政策的生效</span><strong><span lang=\"ZH-TW\" style=\"font-size: 16.0pt; line-height: 172%; font-family: \'Helvetica\',serif;\"> </span></strong></p>\r\n<p><span lang=\"ZH-TW\" style=\"font-size: 11pt; font-family: \'PingFang SC Regular\', serif;\">本隱私政策版本更新日期為</span><span lang=\"EN-US\" style=\"font-size: 11pt; font-family: Helvetica, serif;\">2025</span><span style=\"font-size: 11pt; font-family: \'PingFang SC Regular\', serif;\">年</span><span lang=\"EN-US\" style=\"font-size: 11pt; font-family: Helvetica, serif;\"> 8</span><span style=\"font-size: 11pt; font-family: \'PingFang SC Regular\', serif;\">月</span><span lang=\"EN-US\" style=\"font-size: 11pt; font-family: Helvetica, serif;\">7</span><span lang=\"ZH-TW\" style=\"font-size: 11pt; font-family: \'PingFang SC Regular\', serif;\">日，將於</span><span lang=\"EN-US\" style=\"font-size: 11pt; font-family: Helvetica, serif;\">2025</span><span style=\"font-size: 11pt; font-family: \'PingFang SC Regular\', serif;\">年</span><span lang=\"EN-US\" style=\"font-size: 11pt; font-family: Helvetica, serif;\">8</span><span style=\"font-size: 11pt; font-family: \'PingFang SC Regular\', serif;\">月</span><span lang=\"EN-US\" style=\"font-size: 11pt; font-family: Helvetica, serif;\">8</span><span lang=\"ZH-TW\" style=\"font-size: 11pt; font-family: \'PingFang SC Regular\', serif;\">日正式生效。</span></p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<div id=\"model-response-message-contentr_3c78487baed886ac\" class=\"markdown markdown-main-panel stronger enable-updated-hr-color\" dir=\"ltr\" style=\"font-family: \'Google Sans Text\', sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\" aria-live=\"polite\" aria-busy=\"false\">\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"0\">&nbsp;</p>\r\n<h1 style=\"font-family: \'Google Sans\', sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"2\"><span style=\"font-size: 12pt;\">English Vision：</span></h1>\r\n<h1 style=\"font-family: \'Google Sans\', sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important; text-align: center;\" data-path-to-node=\"2\">LUMOGUIDE Product Privacy Policy</h1>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"3\">This Product is provided by&nbsp;<strong style=\"line-height: 1.15 !important; margin-top: 0px !important;\">LUMOGUIDE</strong>&nbsp;(hereinafter referred to as \"we,\" \"us,\" or \"the Company\"). We recognize the importance of personal information to our users and understand that providing effective protection for your personal data is the cornerstone of our healthy and sustainable business development. Thank you for your trust in our products and services. We solemnly pledge to adopt appropriate security measures in accordance with mature industry safety standards to protect your personal information.</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"4\">Through this Privacy Policy, we aim to explain how we collect, use, store, share, and transfer your personal information when you use our products and services, as well as the methods we provide for you to access, update, delete, and protect this information.</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"5\"><strong style=\"line-height: 1.15 !important; margin-top: 0px !important;\">Please read and understand this Privacy Policy carefully before using our products and services. Use our products or services only after confirming your full understanding and agreement. By starting to use our products and services, you signify that you have fully understood and agreed to this Policy and consent to our collection, use, storage, and sharing of your information in accordance with this Privacy Policy. If you have any questions, comments, or suggestions regarding this Policy, you may contact us through the various contact methods provided herein.</strong></p>\r\n<h3 style=\"font-family: \'Google Sans\', sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"6\">I. Description of Permissions and Access</h3>\r\n<ol style=\"padding-inline-start: 32px; line-height: 1.15 !important; margin-top: 0px !important;\" start=\"1\" data-path-to-node=\"7\">\r\n<li style=\"line-height: 1.15 !important; margin-top: 0px !important;\">\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"7,0,0\"><strong style=\"line-height: 1.15 !important; margin-top: 0px !important;\">Storage Permission:</strong>&nbsp;Dynamically requested; requires user authorization. Used for basic software operation and storage of necessary data.</p>\r\n</li>\r\n<li style=\"line-height: 1.15 !important; margin-top: 0px !important;\">\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"7,1,0\"><strong style=\"line-height: 1.15 !important; margin-top: 0px !important;\">Phone Permission:</strong>&nbsp;Dynamically requested; requires user authorization. We read device status (Device IMSI/IMEI numbers) to display IMEI fields in device configuration checks, for user identification (IMEI will be encrypted during use), account security, business security, and confirming authorized users via device identifiers.</p>\r\n</li>\r\n<li style=\"line-height: 1.15 !important; margin-top: 0px !important;\">\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"7,2,0\"><strong style=\"line-height: 1.15 !important; margin-top: 0px !important;\">Notification Access and Display:</strong>&nbsp;Dynamically requested; requires user authorization. Used for the notification bar cleaning function.</p>\r\n</li>\r\n<li style=\"line-height: 1.15 !important; margin-top: 0px !important;\">\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"7,3,0\"><strong style=\"line-height: 1.15 !important; margin-top: 0px !important;\">Camera Permission:</strong>&nbsp;Dynamically requested; requires user authorization. Used to detect whether camera-related functions are operating normally during mobile device testing.</p>\r\n</li>\r\n<li style=\"line-height: 1.15 !important; margin-top: 0px !important;\">\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"7,4,0\"><strong style=\"line-height: 1.15 !important; margin-top: 0px !important;\">Location Permission:</strong>&nbsp;Dynamically requested; requires user authorization. Used for approximate location acquisition, functional usage statistics, and related features.</p>\r\n</li>\r\n<li style=\"line-height: 1.15 !important; margin-top: 0px !important;\">\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"7,5,0\"><strong style=\"line-height: 1.15 !important; margin-top: 0px !important;\">Auto-start Permission:</strong>&nbsp;Dynamically requested; requires user authorization. Used for functions such as notification bar cleaning.</p>\r\n</li>\r\n<li style=\"line-height: 1.15 !important; margin-top: 0px !important;\">\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"7,6,0\"><strong style=\"line-height: 1.15 !important; margin-top: 0px !important;\">Recording (Microphone) Permission:</strong>&nbsp;Dynamically requested; requires user authorization. Used for basic audio and video calling features.</p>\r\n</li>\r\n</ol>\r\n<h3 style=\"font-family: \'Google Sans\', sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"8\">II. Rights to Manage Personal Information</h3>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">(1) Access and Correct Your Personal Information</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">You have the right to access your personal information, except as otherwise provided by laws and regulations. You may contact us at any time via our Web form entry at [My] &rarr; [Settings] &rarr; [Feedback]. We will respond to your access request within 15 days. For other personal information generated during your use of our products or services, we will provide it to you as long as it does not require excessive investment from us.</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">(2) Delete Your Personal Information</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">You have the right to request the deletion of your personal information in the following circumstances:</p>\r\n<ol style=\"padding-inline-start: 32px; line-height: 1.15 !important; margin-top: 0px !important;\" start=\"1\" data-path-to-node=\"11\">\r\n<li style=\"line-height: 1.15 !important; margin-top: 0px !important;\">\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"11,0,0\">We collected your personal information without seeking your explicit consent.</p>\r\n</li>\r\n<li style=\"line-height: 1.15 !important; margin-top: 0px !important;\">\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"11,1,0\">Our processing of your personal information violates legal or regulatory requirements.</p>\r\n</li>\r\n<li style=\"line-height: 1.15 !important; margin-top: 0px !important;\">\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"11,2,0\">Our use and processing of your personal information violate our agreement with you.</p>\r\n</li>\r\n<li style=\"line-height: 1.15 !important; margin-top: 0px !important;\">\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"11,3,0\">You have canceled your account, uninstalled the app, or ceased using our products (or services).</p>\r\n</li>\r\n<li style=\"line-height: 1.15 !important; margin-top: 0px !important;\">\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">We cease providing services to you.</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">You may contact us to request the deletion of your personal information through the methods provided in this Privacy Policy.</p>\r\n</li>\r\n</ol>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">(3) Cancel Your Personal Account</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">You may cancel your previously registered account at any time. You can perform this action yourself via the following path: [My] &rarr; [Settings] &rarr; [Account Management] &rarr; [Account Cancellation].</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">Upon account cancellation, we will stop providing products or services to you and, at your request, delete your personal information, unless otherwise provided by laws and regulations. Please understand that once data is deleted, it cannot be recovered. To ensure account security, we may need to verify your identity before manual review and confirmation of your cancellation request.</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"13\"><strong style=\"line-height: 1.15 !important; margin-top: 0px !important;\">(4) Withdrawal of Consent or Authorization</strong></p>\r\n<ol style=\"padding-inline-start: 32px; line-height: 1.15 !important; margin-top: 0px !important;\" start=\"1\" data-path-to-node=\"14\">\r\n<li style=\"line-height: 1.15 !important; margin-top: 0px !important;\">\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"14,0,0\">Each business function requires certain basic personal information to be completed. For the collection and use of additional personal information, you may grant or withdraw your authorization and consent at any time.</p>\r\n</li>\r\n<li style=\"line-height: 1.15 !important; margin-top: 0px !important;\">\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"14,1,0\">You can perform this yourself by adjusting the APP\'s authorizations within your mobile phone system settings.</p>\r\n</li>\r\n<li style=\"line-height: 1.15 !important; margin-top: 0px !important;\">\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"14,2,0\">Once you withdraw your consent, we will no longer process the corresponding personal information. However, your decision to withdraw consent will not affect the personal information processing previously carried out based on your authorization.</p>\r\n</li>\r\n</ol>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">(5) Responding to Your Requests Above</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">To ensure security, you may be required to provide a written request or otherwise prove your identity. We may ask you to verify your identity before processing your request. Please understand that due to legal requirements, information security protection, or technical limitations, some of your information may not be accessible, modifiable, or deletable.</p>\r\n<h3 style=\"font-family: \'Google Sans\', sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"16\">III. Protection of Minors\' Personal Information</h3>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">If you are a minor under the age of 18, you should obtain prior consent from your parent or legal guardian before using our products and services.</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">If you are a child under the age of 14, you must read this Privacy Policy (or the specific product/service privacy policy) accompanied by a guardian before deciding whether to use our products or services. If personal information must be submitted to obtain products or services, please obtain the guardian\'s consent and complete the process under their guidance. If you are the guardian of a child, you should carefully read this Policy or specific privacy policies before helping the child register or use the products/services. If you have questions about the personal information of the child under your guardianship, please contact us via the methods in Section VI.</p>\r\n<h3 style=\"font-family: \'Google Sans\', sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"18\">IV. Scope of Applicability</h3>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"19\">This Privacy Policy applies only to the Android and iOS versions. Our other products and services will use their respective privacy policies. Specifically, this Privacy Policy does&nbsp;<strong style=\"line-height: 1.15 !important; margin-top: 0px !important;\">not</strong>&nbsp;apply to:</p>\r\n<ol style=\"padding-inline-start: 32px; line-height: 1.15 !important; margin-top: 0px !important;\" start=\"1\" data-path-to-node=\"20\">\r\n<li style=\"line-height: 1.15 !important; margin-top: 0px !important;\">\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"20,0,0\">Information collected by third-party products (or services) when our products (or services) are embedded within them.</p>\r\n</li>\r\n<li style=\"line-height: 1.15 !important; margin-top: 0px !important;\">\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">Information collected by third-party services, advertisements, or other companies, organizations, or individuals accessed through our products (or services).</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">We remind you to carefully read the relevant user agreements and privacy policies provided by third parties when using their products and/or services, and to protect your personal information diligently.</p>\r\n</li>\r\n</ol>\r\n<h3 style=\"font-family: \'Google Sans\', sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"21\">V. Changes and Amendments to the Privacy Policy</h3>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">Our Privacy Policy may change. We will not restrict your rights under this Privacy Policy without your explicit consent. For material changes, we will provide prominent notices (e.g., timely notification via pop-up windows during software revisions, upgrades, or when you log in again).</p>\r\n<p style=\"padding-top: 0px; padding-bottom: 0px; line-height: 1.15 !important; margin-top: 0px !important;\">Material changes referred to in this Policy include, but are not limited to:</p>\r\n<ol style=\"padding-inline-start: 32px; line-height: 1.15 !important; margin-top: 0px !important;\" start=\"1\" data-path-to-node=\"23\">\r\n<li style=\"line-height: 1.15 !important; margin-top: 0px !important;\">\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"23,0,0\">Significant changes in our service model (e.g., purpose of processing, types of personal information processed, or usage methods).</p>\r\n</li>\r\n<li style=\"line-height: 1.15 !important; margin-top: 0px !important;\">\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"23,1,0\">Significant changes in our control (e.g., changes in ownership caused by mergers or reorganizations).</p>\r\n</li>\r\n<li style=\"line-height: 1.15 !important; margin-top: 0px !important;\">\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"23,2,0\">Changes in the primary parties with whom personal information is shared, transferred, or publicly disclosed.</p>\r\n</li>\r\n<li style=\"line-height: 1.15 !important; margin-top: 0px !important;\">\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"23,3,0\">Significant changes in your rights regarding personal information processing and how to exercise them.</p>\r\n</li>\r\n<li style=\"line-height: 1.15 !important; margin-top: 0px !important;\">\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"23,4,0\">Changes in the department responsible for personal information security, contact information, or complaint channels.</p>\r\n</li>\r\n<li style=\"line-height: 1.15 !important; margin-top: 0px !important;\">\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"23,5,0\">When a personal information security impact assessment report indicates a high risk.</p>\r\n</li>\r\n</ol>\r\n<h3 style=\"font-family: \'Google Sans\', sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"24\">VI. How to Contact Us</h3>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"25\">If you have any questions, comments, suggestions, or complaints regarding our Privacy Policy or the processing of your personal information, please contact us via Email at:&nbsp;<strong style=\"line-height: 1.15 !important; margin-top: 0px !important;\">support@lumoguide.com</strong></p>\r\n<h3 style=\"font-family: \'Google Sans\', sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"26\">VII. Effectiveness of the Privacy Policy</h3>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">The version of this Privacy Policy was updated on&nbsp;<strong style=\"line-height: 1.15 !important; margin-top: 0px !important;\">August 7, 2025</strong>, and will officially take effect on&nbsp;<strong style=\"line-height: 1.15 !important; margin-top: 0px !important;\">August 8, 2025</strong>.</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">&nbsp;</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">简体中文版：</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important; text-align: center;\" data-path-to-node=\"27\"><span style=\"font-size: 24pt;\">《路盟产品隐私政策》</span></p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">本款产品由LUMOGUIDE（以下简称「我们」）提供。我们深知个人信息对用户的重要性，也深知为用户的个人信息提供有效保护是我们业务健康可持续发展的基石。感谢您对我们产品和服务的使用和信任！我们郑重承诺，我们将按业界成熟的安全标准，采取相应的安全保护措施来保护您的个人信息。我们希望通过本隐私政策向您说明，在使用我们的产品和服务时，我们如何收集、使用、存储、分享和转让您的个人信息，以及我们为您提供的访问、更新、删除和保护这些信息的方式。</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">&nbsp;</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">请在使用我们的产品和服务前，务必仔细阅读并了解本隐私政策，在确认充分理解并同意后使用我们的产品或服务。一旦您开始使用我们的产品和服务，即表示您已充分理解并同意本政策，并同意我们按照本隐私政策收集、使用、储存和分享您的相关信息。如对本政策内容有任何疑问、意见或建议，您可通过本隐私政策提供的各种联系方式与我们联系。</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">&nbsp;</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">一.获取权限说明</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">&nbsp;</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">1.获取存储权限，设备授权，动态获取，需要用户授权。用户基础的软件使用。</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">2.电话权限，动态获取，需要用户授权。读取电话状态（设备IMSI/IMEI号）用于展示验机手机配置中IMEI号字段内容；用于用户身份识别（使用中我们会将IMEI进行加密），账号安全，业务安全等需要；获取设备识别码用于权限用户的确认等。</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">3.通知读取和展示权限，动态获取，需要用户授权。用于通知栏清理功能。</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">4.相机拍摄权限，动态获取，需要用户授权。用于完成手机检测时检测相机相关功能是否正常。</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">5.位置权限，动态获取，需要用户授权。粗略获取位置，功能使用统计等功能；</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">6.自启动权限，动态获取，需要用户授权。用于通知栏清理等功能。</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">7.录音权限，动态获取，需要用户授权。用于基本音视频通话使用。</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">&nbsp;</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">二.管理个人信息的权利</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">（一）访问和更正您的个人信息</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">您有权访问您的个人信息，法律法规规定的例外情况除外。您可以随时使用我们的 Web 表单联系入口在【我的】&rarr;【设置】&rarr;【反馈】我们将在15天内回复您的访问请求。</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">对于您在使用我们的产品或服务过程中产生的其他个人信息，只要我们不需要过多投入，我们会向您提供。</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">（二）删除您的个人信息</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">以下情况发生时，您有权要求我们删除您的个人信息：</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">1. 我们没有征求您的明确同意，收集了您的个人信息。</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">2. 我们处理您的个人信息违反了法律法规要求。</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">3. 我们违反了与您的约定来使用和处理您的个人信息。</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">4. 您注销了账号、卸载或者不再使用我们的产品（或服务）。</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">5. 我们停止对您提供服务。</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">您可以通过本隐私政策提供的方式联系我们要求删除您的个人信息。</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">&nbsp;</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">（三）注销您的个人账户</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">您随时可注销此前注册的账户，您可以通过以下方式自行操作：操作路径为【我的】&rarr;【设置】&rarr;【账号管理】&rarr;【账号注销】进行操作。</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">在注销账户之后，我们将停止为您提供产品或服务，并依据您的要求，删除您的个人信息，法律法规另有规定的除外。这些一旦删除将不可以恢复，因此请您理解，在您提交申请后，为保障账号安全，我们可能需要验证您的身份后再进行人工审核和确认。</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">（四）撤回您的同意或授权</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">1. 每个业务功能需要一些基本的个人信息才能得以完成。对于额外收集的个人信息的收集和使用，您可以随时给予或收回您的授权同意。</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">2. 您可以通过以下方式自行操作：通过手机系统设置调整对APP的授权。</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">3. 当您收回同意后，我们将不再处理相应的个人信息。但您收回同意的决定，不会影响此前基于您的授权而开展的个人信息处理。</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">（五）响应您的上述请求</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">为保障安全，您可能需要提供书面请求，或以其他方式证明您的身份。我们可能会先要求您验证自己的身份，然后再处理您的请求。但请您理解，基于法律法规要求、保障信息安全、技术限制等原因，您的部分信息可能无法访问、修改和删除。</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">&nbsp;</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">三.未成年人个人信息保护</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">若您是18周岁以下的未成年人，在使用我们的产品和服务前，应事先取得您的家长或法定监护人的同意。</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">若您是未满14周岁的儿童，须在监护人的陪同下阅读本隐私政策或相应产品或服务的隐私政策，决定是否使用我们的产品或服务。如获得产品和服务需要提交个人信息，请取得监护人的同意，并在监护人的指导下完成。若您是儿童的监护人，当您在帮助儿童完成产品或服务的注册、使用前，应当仔细阅读本政策或特定产品的隐私保护政策，决定是否同意隐私政策。当您对您所监护的儿童的个人信息有疑问时，您可以通过本隐私政策第九节的联系方式与我们联系。</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">&nbsp;</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">四.隐私政策的适用范围</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">本私政策仅适用于安卓版、IOS版。我们的其他产品和服务将使用相关产品或服务的隐私政策。特别需要说明的是，本隐私政策不适用以下情况：</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">1. 将我们的产品（或服务）嵌入到第三方产品（或服务），第三方产品（或服务）收集的信息。</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">2. 在我们的产品（或服务）中接入的第三方服务、广告或其他公司、组织或个人所收集的信息。</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">我们在此提醒您，您在使用第三方产品与/或服务时，请仔细阅读第三方向您展示的相关用户协议和隐私政策，并妥善保管和谨慎提供您的个人信息。</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">&nbsp;</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">五.隐私政策的变更和修订</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">我们的隐私政策可能变更。未经您明确同意，我们不会限制您按照本隐私政策所应享有的权利。对于本隐私政策的重大变更，我们还会提供显著的通知（例如，在软件改版或升级、或您重新登录时，以弹窗形式对您进行及时通知）。</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">&nbsp;</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">本政策所指的重大变更包括但不限于：</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">1. 我们的服务模式发生重大变化。如处理个人信息的目的、处理的个人信息类型、个人信息的使用方式等；</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">2. 我们在控制权等方面发生重大变化。如并购重组等引起的所有者变更等；</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">3. 个人信息共享、转让或公开披露的主要对象发生变化；</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">4. 您参与个人信息处理方面的权利及其行使方式发生重大变化；</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">5. 我们负责处理个人信息安全的责任部门、联络方式及投诉渠道发生变化时；</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">6. 个人信息安全影响评估报告表明存在高风险时。</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">&nbsp;</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">六.如何联系我们</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">如果您对我们的隐私政策及对您个人信息的处理有任何疑问、意见、建议或投诉，请通过以下方式与我们联系， Email：support@lumoguide.com</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">&nbsp;</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">七.隐私政策的生效</p>\r\n<p style=\"line-height: 1.15 !important; margin-top: 0px !important;\" data-path-to-node=\"27\">本隐私政策版本更新日期为2025年 8月7日，将于2025年8月8日正式生效。</p>\r\n</div>','2025-06-16 19:54:27','2025-12-21 02:53:26'),(3,'聯系我們',4,'contact_us','請透過以下方式聯繫我們：\r\n\r\nLUMOGUIDE App在线客服\r\n\r\n客服郵箱：support@lumoguide.com\r\n\r\n官方網站：https://www.lumoguide.com\r\n\r\n感謝您使用 Lumo Guide！','2025-07-24 08:55:01','2025-12-21 03:07:04'),(4,'LUMO FUN積分規則',2,'integral_rule','<p style=\"margin: 0px 0px 14.9px; font-style: normal; font-variant-caps: normal; font-stretch: normal; font-size: 18px; line-height: normal; font-family: \'PingFang HK Semibold\'; font-size-adjust: none; font-kerning: auto; font-variant-alternates: normal; font-variant-ligatures: normal; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-position: normal; font-feature-settings: normal; font-optical-sizing: auto; font-variation-settings: normal; text-align: center;\"><strong><span style=\"font-style: normal; font-variant-caps: normal; font-stretch: normal; line-height: normal; font-family: \'PingFang HK\'; font-size-adjust: none; font-kerning: auto; font-variant-alternates: normal; font-variant-ligatures: normal; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-position: normal; font-variant-emoji: normal; font-feature-settings: normal; font-optical-sizing: auto; font-variation-settings: normal;\">積分使用與服務條款</span></strong></p>\r\n<p style=\"margin: 0px 0px 14px; font-style: normal; font-variant-caps: normal; font-stretch: normal; font-size: 14px; line-height: normal; font-family: \'PingFang HK Semibold\'; font-size-adjust: none; font-kerning: auto; font-variant-alternates: normal; font-variant-ligatures: normal; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-position: normal; font-variant-emoji: normal; font-feature-settings: normal; font-optical-sizing: auto; font-variation-settings: normal;\"><span style=\"font-style: normal; font-variant-caps: normal; font-stretch: normal; line-height: normal; font-family: \'PingFang HK\'; font-size-adjust: none; font-kerning: auto; font-variant-alternates: normal; font-variant-ligatures: normal; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-position: normal; font-variant-emoji: normal; font-feature-settings: normal; font-optical-sizing: auto; font-variation-settings: normal;\"><strong>一、 積分之法律性質與限制</strong></span></p>\r\n<ol>\r\n<li style=\"margin: 0px 0px 12px; font-style: normal; font-variant-caps: normal; font-stretch: normal; font-size: 11px; line-height: normal; font-family: \'PingFang HK\'; font-size-adjust: none; font-kerning: auto; font-variant-alternates: normal; font-variant-ligatures: normal; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-position: normal; font-variant-emoji: normal; font-feature-settings: normal; font-optical-sizing: auto; font-variation-settings: normal;\"><strong>定義與性質</strong>：本應用程式（以下簡稱「本平台」）所發行之積分，係本平台發行之虛擬獎勵，非屬法定貨幣。積分僅供用戶於本平台內部依指定規則使用，不具備任何經濟價值或貨幣兌換性。</li>\r\n<li style=\"margin: 0px 0px 12px; font-style: normal; font-variant-caps: normal; font-stretch: normal; font-size: 11px; line-height: normal; font-family: \'PingFang HK\'; font-size-adjust: none; font-kerning: auto; font-variant-alternates: normal; font-variant-ligatures: normal; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-position: normal; font-variant-emoji: normal; font-feature-settings: normal; font-optical-sizing: auto; font-variation-settings: normal;\"><strong>限制行為</strong>：積分僅限於原獲取帳戶內使用，<strong>嚴禁轉讓、質押、贈與或繼承</strong>。用戶不得要求將積分兌換為現金、折現或申請退款。任何私自交易積分之行為，本平台有權不予承認並逕行沒收相關積分。</li>\r\n</ol>\r\n<p style=\"margin: 0px 0px 14px; font-style: normal; font-variant-caps: normal; font-stretch: normal; font-size: 14px; line-height: normal; font-family: \'PingFang HK Semibold\'; font-size-adjust: none; font-kerning: auto; font-variant-alternates: normal; font-variant-ligatures: normal; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-position: normal; font-variant-emoji: normal; font-feature-settings: normal; font-optical-sizing: auto; font-variation-settings: normal;\"><span style=\"font-style: normal; font-variant-caps: normal; font-stretch: normal; line-height: normal; font-family: \'PingFang HK\'; font-size-adjust: none; font-kerning: auto; font-variant-alternates: normal; font-variant-ligatures: normal; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-position: normal; font-variant-emoji: normal; font-feature-settings: normal; fon